const SUPABASE_URL = 'https://dmpcrwzxzosuerjyrdcd.supabase.co';
const SUPABASE_KEY = 'eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpc3MiOiJzdXBhYmFzZSIsInJlZiI6ImRtcGNyd3p4em9zdWVyanlyZGNkIiwicm9sZSI6ImFub24iLCJpYXQiOjE3ODIwMTg3OTYsImV4cCI6MjA5NzU5NDc5Nn0._bkf9MqBp5Nkg4m3aaLExh-CD_V0SDaiSbJZGvrlDbk';
const ORDERS_TABLE = 'orders';
const POLL_INTERVAL_MS = 4000; // how often devices check for new/updated orders

// ---------- Supabase REST helpers (no SDK needed, just fetch) ----------
async function sbFetch(path, options = {}) {
  const res = await fetch(`${SUPABASE_URL}/rest/v1/${path}`, {
    ...options,
    headers: {
      'apikey': SUPABASE_KEY,
      'Authorization': `Bearer ${SUPABASE_KEY}`,
      'Content-Type': 'application/json',
      ...(options.headers || {}),
    },
  });
  if (!res.ok) {
    const text = await res.text().catch(() => '');
    throw new Error(`Supabase ${options.method || 'GET'} ${path} failed: ${res.status} ${text}`);
  }
  // 204 No Content (e.g. some PATCH/DELETE responses) has no body to parse
  if (res.status === 204) return null;
  return res.json();
}

// Fetch all orders from the last N hours, newest first
async function fetchOrders() {
  try {
    const sinceIso = new Date(Date.now() - 24 * 60 * 60 * 1000).toISOString();
    const rows = await sbFetch(
      `${ORDERS_TABLE}?select=order_id,data,created_at&created_at=gte.${sinceIso}&order=created_at.asc`
    );
    const parsed = (rows || [])
      .map(row => { try { return JSON.parse(row.data); } catch (e) { return null; } })
      .filter(Boolean);
    return { orders: parsed, error: null };
  } catch (e) {
    console.warn('fetchOrders failed', e);
    return { orders: null, error: e.message || String(e) };
  }
}

// Insert a brand new order row
async function insertOrder(order) {
  try {
    await sbFetch(ORDERS_TABLE, {
      method: 'POST',
      body: JSON.stringify({ order_id: order.id, data: JSON.stringify(order) }),
    });
    return true;
  } catch (e) {
    console.warn('insertOrder failed', e);
    return false;
  }
}

// Update an existing order row (full row replace, simplest for this scale)
async function updateOrderRemote(order) {
  try {
    await sbFetch(`${ORDERS_TABLE}?order_id=eq.${encodeURIComponent(order.id)}`, {
      method: 'PATCH',
      headers: { 'Prefer': 'return=minimal' },
      body: JSON.stringify({ data: JSON.stringify(order) }),
    });
    return true;
  } catch (e) {
    console.warn('updateOrderRemote failed', e);
    return false;
  }
}

function genOrderId() {
  return 'o' + Date.now().toString(36) + Math.random().toString(36).slice(2, 6);
}
function genOrderNumber() {
  return Math.floor(1000 + Math.random() * 9000);
}

// ---------- Root App ----------
export default function App() {
  const [view, setView] = useState('loading'); // loading | customer | kitchen
  const [lang, setLang] = useState('ar');
  const [orders, setOrders] = useState([]); // shared order list — single source of truth
  const [dbError, setDbError] = useState(null);
  const pollRef = useRef(null);

  useEffect(() => {
    // Simple hash-based routing: #kitchen or #table=5
    const hash = window.location.hash || '';
    if (hash.includes('kitchen')) {
      setView('kitchen');
    } else {
      setView('customer');
    }

    // initial load + poll for cross-device sync (this is a static frontend,
    // so polling is the simplest reliable way for two different phones/tablets to see the same orders)
    const sync = async () => {
      const { orders: fresh, error } = await fetchOrders();
      if (error) {
        setDbError(error);
      } else {
        setDbError(null);
        setOrders(fresh);
      }
    };
    sync();
    pollRef.current = setInterval(sync, POLL_INTERVAL_MS);
    return () => clearInterval(pollRef.current);
  }, []);

  const addOrder = useCallback((order) => {
    setOrders(prev => [...prev, order]);
    insertOrder(order); // fire and forget; next poll will reconcile either way
  }, []);

  const updateOrder = useCallback((orderId, updates) => {
    setOrders(prev => {
      const next = prev.map(o => o.id === orderId ? { ...o, ...updates } : o);
      const updated = next.find(o => o.id === orderId);
      if (updated) updateOrderRemote(updated);
      return next;
    });
  }, []);

  if (view === 'loading') return <LoadingScreen />;
  if (view === 'kitchen') return <KitchenApp lang={lang} setLang={setLang} orders={orders} updateOrder={updateOrder} dbError={dbError} goCustomer={() => { window.location.hash = ''; setView('customer'); }} />;
  return <CustomerApp lang={lang} setLang={setLang} orders={orders} addOrder={addOrder} dbError={dbError} goKitchen={() => { window.location.hash = 'kitchen'; setView('kitchen'); }} />;
}

function LoadingScreen() {
  return (
    <div style={{ minHeight: '100vh', background: '#161310', display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
      <Loader2 className="animate-spin" color="#C9A24B" size={32} />
    </div>
  );
}

/* ============================================================
   CUSTOMER APP
   ============================================================ */
function CustomerApp({ lang, setLang, orders, addOrder, dbError, goKitchen }) {
  const t = STR[lang];
  const [table, setTable] = useState(null);
  const [screen, setScreen] = useState('splash'); // splash | tablepicker | menu | item | cart | checkout | confirmed | tracking
  const [cart, setCart] = useState([]); // {key, itemId, name, basePrice, qty, addons:[{id,name,price}], notes}
  const [activeItem, setActiveItem] = useState(null);
  const [sessionOrderIds, setSessionOrderIds] = useState([]);
  const [lastOrderData, setLastOrderData] = useState(null); // fallback so confirmed screen never goes blank

  const addSessionOrderId = (id) => {
    setSessionOrderIds(prev => {
      const next = [...prev, id];
      try { localStorage.setItem('freshcafe_sessionOrderIds', JSON.stringify(next)); } catch (e) {}
      return next;
    });
  };

  useEffect(() => {
    const hash = window.location.hash || '';
    const m = hash.match(/table=(\d+)/);
    if (m) {
      setTable(parseInt(m[1], 10));
      setScreen('menu');
    }
    // restore any in-progress orders for this device/tab
    try {
      const saved = localStorage.getItem('freshcafe_sessionOrderIds');
      if (saved) setSessionOrderIds(JSON.parse(saved));
    } catch (e) {}
  }, []);

  // all tracked orders for this session, live from Supabase polling
  const trackedOrders = sessionOrderIds
    .map(id => orders.find(o => o.id === id))
    .filter(Boolean);
  // fallback: if polling hasn't returned yet, use the last placed order directly
  const trackedOrdersFull = trackedOrders.length > 0 ? trackedOrders
    : (lastOrderData ? [lastOrderData] : []);
  const hasActiveOrders = trackedOrdersFull.some(o => o.status !== 'done');

  const cartTotal = cart.reduce((sum, c) => {
    const addonsTotal = c.addons.reduce((a, ad) => a + ad.price, 0);
    return sum + (c.basePrice + addonsTotal) * c.qty;
  }, 0);
  const cartCount = cart.reduce((sum, c) => sum + c.qty, 0);

  const addToCart = (entry) => {
    setCart(prev => [...prev, entry]);
  };
  const updateQty = (key, delta) => {
    setCart(prev => prev.map(c => c.key === key ? { ...c, qty: Math.max(1, c.qty + delta) } : c).filter(c => c.qty > 0));
  };
  const removeItem = (key) => setCart(prev => prev.filter(c => c.key !== key));

  const placeOrder = async (paymentMeta) => {
    const orderId = genOrderId();
    const orderNumber = genOrderNumber();
    const order = {
      id: orderId,
      number: orderNumber,
      table,
      items: cart,
      total: cartTotal,
      status: 'new',
      createdAt: Date.now(),
      payment: paymentMeta,
    };
    addOrder(order);
    addSessionOrderId(orderId);
    setLastOrderData(order);
    setCart([]);
    setScreen('confirmed');
  };

  return (
    <div dir={t.dir} style={{
      minHeight: '100vh', background: '#161310', color: '#F2EBDD',
      fontFamily: lang === 'ar' ? "'Noto Sans Arabic', 'Segoe UI', sans-serif" : "'Noto Sans Hebrew', 'Segoe UI', sans-serif",
      paddingBottom: cart.length > 0 && (screen === 'menu') ? '88px' : 0,
    }}>
      <style>{GLOBAL_CSS}</style>

      {screen === 'splash' && (
        <SplashScreen lang={lang} setLang={setLang} onEnter={() => setScreen('tablepicker')}
          onTrack={hasActiveOrders ? () => setScreen('tracking') : null} />
      )}

      {screen === 'tablepicker' && (
        <TablePicker t={t} lang={lang} setLang={setLang} onPick={(n) => { setTable(n); setScreen('menu'); }} />
      )}

      {screen === 'menu' && (
        <>
          <CustomerHeader t={t} lang={lang} setLang={setLang} table={table} />
          {hasActiveOrders && (
            <button onClick={() => setScreen('tracking')} style={{
              display: 'flex', alignItems: 'center', justifyContent: 'space-between', width: '100%',
              margin: '10px 14px 0', padding: '11px 14px', borderRadius: 12, background: 'rgba(201,162,75,0.1)',
              border: '1px solid #C9A24B', color: '#C9A24B', fontSize: 13, fontWeight: 600, cursor: 'pointer'
            }}>
              <span>{trackedOrdersFull.length > 1 ? `${trackedOrdersFull.length} ${t.activeOrders || 'طلبات نشطة'}` : `#${trackedOrdersFull[0]?.number} · ${t.table} ${table}`}</span>
              <span>{t.viewOrder} →</span>
            </button>
          )}
          <MenuBrowser t={t} lang={lang} onSelectItem={(item) => { setActiveItem(item); setScreen('item'); }} />
          {cartCount > 0 && (
            <CartFab t={t} count={cartCount} total={cartTotal} onClick={() => setScreen('cart')} />
          )}
        </>
      )}

      {screen === 'item' && activeItem && (
        <ItemDetail
          t={t} lang={lang} item={activeItem}
          onBack={() => setScreen('menu')}
          onAdd={(entry) => { addToCart(entry); setScreen('menu'); }}
        />
      )}

      {screen === 'cart' && (
        <CartScreen
          t={t} lang={lang} cart={cart} total={cartTotal}
          onBack={() => setScreen('menu')}
          onUpdateQty={updateQty}
          onRemove={removeItem}
          onCheckout={() => setScreen('checkout')}
        />
      )}

      {screen === 'checkout' && (
        <CheckoutScreen
          t={t} lang={lang} cart={cart} total={cartTotal} table={table}
          onBack={() => setScreen('cart')}
          onPaid={placeOrder}
        />
      )}

      {screen === 'confirmed' && lastOrderData && (
        <ConfirmedScreen
          t={t} lang={lang} order={lastOrderData} table={table}
          onNewOrder={() => setScreen('menu')}
          onTrack={() => setScreen('tracking')}
        />
      )}

      {screen === 'tracking' && trackedOrdersFull.length > 0 && (
        <TrackingScreen
          t={t} lang={lang} orders={trackedOrdersFull}
          onNewOrder={() => setScreen('menu')}
        />
      )}

    </div>
  );
}

