function TablePicker({ t, lang, setLang, onPick }) {
  const [value, setValue] = useState('');
  const num = parseInt(value, 10);
  const valid = value.trim() !== '' && Number.isInteger(num) && num > 0;

  return (
    <div style={{ minHeight: '100vh', display: 'flex', flexDirection: 'column', alignItems: 'center', padding: '40px 20px' }}>
      <style>{GLOBAL_CSS}</style>
      <LangToggle t={t} lang={lang} setLang={setLang} style={{ alignSelf: lang === 'ar' ? 'flex-start' : 'flex-end' }} />
      <div style={{ marginTop: 24, marginBottom: 8 }}>
        <Logo />
      </div>
      <h1 style={{ fontFamily: 'var(--display)', fontSize: 32, color: '#C9A24B', margin: '8px 0 2px', textAlign: 'center', letterSpacing: 0.5 }}>
        Fresh Cafe' &amp; Market
      </h1>
      <p style={{ color: '#9B9384', fontSize: 14, marginBottom: 36 }}>{t.tagline}</p>

      <p style={{ color: '#F2EBDD', fontSize: 16, marginBottom: 16, fontWeight: 600 }}>{t.enterTableNumber}</p>
      <input
        type="number"
        inputMode="numeric"
        min="1"
        value={value}
        onChange={e => setValue(e.target.value)}
        placeholder={t.tableNumberPlaceholder}
        style={{
          width: '100%', maxWidth: 360, padding: '20px', borderRadius: 14, textAlign: 'center',
          fontSize: 32, fontWeight: 700, color: '#C9A24B', background: '#1E1A15',
          border: '1.5px solid #3A352C', boxSizing: 'border-box', fontFamily: 'inherit'
        }}
      />

      <button disabled={!valid} onClick={() => onPick(num)}
        style={{
          marginTop: 24, width: '100%', maxWidth: 360, padding: '16px', borderRadius: 12,
          background: valid ? '#C9A24B' : '#3A352C', color: valid ? '#161310' : '#6b6457',
          fontWeight: 700, fontSize: 16, border: 'none', cursor: valid ? 'pointer' : 'not-allowed',
        }}>
        {t.start}
      </button>
    </div>
  );
}

