function ItemDetail({ t, lang, item, onBack, onAdd }) {
  const [qty, setQty] = useState(1);
  const [selectedAddons, setSelectedAddons] = useState([]);
  const [notes, setNotes] = useState('');
  const group = item.addonGroupId ? ADDON_GROUPS[item.addonGroupId] : null;

  const toggleAddon = (opt) => {
    setSelectedAddons(prev => {
      const exists = prev.find(a => a.id === opt.id);
      if (exists) return prev.filter(a => a.id !== opt.id);
      return [...prev, { id: opt.id, name: opt.name[lang], price: opt.price }];
    });
  };

  const addonsTotal = selectedAddons.reduce((s, a) => s + a.price, 0);
  const lineTotal = (item.price + addonsTotal) * qty;

  const BackIcon = lang === 'ar' ? ArrowRight : ArrowLeft;

  return (
    <div style={{ minHeight: '100vh', display: 'flex', flexDirection: 'column' }}>
      <div style={{ padding: '14px 16px', borderBottom: '1px solid #2A251E', display: 'flex', alignItems: 'center', gap: 12 }}>
        <button onClick={onBack} style={{ background: 'none', border: 'none', color: '#C9A24B', cursor: 'pointer', padding: 4 }}>
          <BackIcon size={22} />
        </button>
        <span style={{ color: '#9B9384', fontSize: 13 }}>{t.customize}</span>
      </div>

      <div style={{ padding: '20px 18px', flex: 1, overflowY: 'auto' }}>
        {item.image && (
          <img src={item.image} alt="" style={{
            width: '100%', height: 200, objectFit: 'cover', borderRadius: 14, marginBottom: 18,
            border: '1px solid #2A251E'
          }} />
        )}
        <h2 style={{ fontFamily: 'var(--display)', fontSize: 24, color: '#F2EBDD', margin: '0 0 4px' }}>{item.name[lang]}</h2>
        {item.desc && <p style={{ color: '#9B9384', fontSize: 14, margin: '0 0 8px', lineHeight: 1.5 }}>{item.desc[lang]}</p>}
        <p style={{ color: '#C9A24B', fontSize: 18, fontWeight: 700, margin: '8px 0 24px' }}>{item.price} {t.shekel}</p>

        {group && (
          <div style={{ marginBottom: 28 }}>
            <div style={{ display: 'flex', alignItems: 'baseline', gap: 8, marginBottom: 12 }}>
              <span style={{ color: '#F2EBDD', fontWeight: 700, fontSize: 15 }}>{group.label[lang]}</span>
              <span style={{ color: '#6b6457', fontSize: 12 }}>{t.optional}</span>
            </div>
            <div style={{ display: 'flex', flexDirection: 'column', gap: 8 }}>
              {group.options.map(opt => {
                const checked = selectedAddons.some(a => a.id === opt.id);
                return (
                  <button key={opt.id} onClick={() => toggleAddon(opt)}
                    style={{
                      display: 'flex', alignItems: 'center', justifyContent: 'space-between',
                      padding: '12px 14px', borderRadius: 10, cursor: 'pointer',
                      border: checked ? '1.5px solid #C9A24B' : '1px solid #2A251E',
                      background: checked ? 'rgba(201,162,75,0.1)' : '#1B1712',
                    }}>
                    <span style={{ display: 'flex', alignItems: 'center', gap: 10 }}>
                      <span style={{
                        width: 20, height: 20, borderRadius: 5, border: checked ? '1.5px solid #C9A24B' : '1.5px solid #4A4536',
                        background: checked ? '#C9A24B' : 'transparent', display: 'flex', alignItems: 'center', justifyContent: 'center'
                      }}>
                        {checked && <Check size={13} color="#161310" strokeWidth={3} />}
                      </span>
                      <span style={{ color: '#F2EBDD', fontSize: 14 }}>{opt.name[lang]}</span>
                    </span>
                    <span style={{ color: '#9B9384', fontSize: 13 }}>+{opt.price} {t.shekel}</span>
                  </button>
                );
              })}
            </div>
          </div>
        )}

        <div style={{ marginBottom: 24 }}>
          <span style={{ color: '#F2EBDD', fontWeight: 700, fontSize: 15, display: 'block', marginBottom: 10 }}>{t.notes}</span>
          <textarea value={notes} onChange={e => setNotes(e.target.value)} placeholder={t.notesPlaceholder}
            rows={2}
            style={{
              width: '100%', background: '#1B1712', border: '1px solid #2A251E', borderRadius: 10,
              padding: '12px', color: '#F2EBDD', fontSize: 14, resize: 'none', fontFamily: 'inherit'
            }} />
        </div>

        <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'center', gap: 20, marginBottom: 8 }}>
          <button onClick={() => setQty(q => Math.max(1, q - 1))}
            style={{ width: 40, height: 40, borderRadius: '50%', border: '1px solid #3A352C', background: '#1E1A15', color: '#F2EBDD', cursor: 'pointer', display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
            <Minus size={16} />
          </button>
          <span style={{ fontSize: 20, fontWeight: 700, minWidth: 24, textAlign: 'center' }}>{qty}</span>
          <button onClick={() => setQty(q => q + 1)}
            style={{ width: 40, height: 40, borderRadius: '50%', border: '1px solid #3A352C', background: '#1E1A15', color: '#F2EBDD', cursor: 'pointer', display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
            <Plus size={16} />
          </button>
        </div>
      </div>

      <div style={{ padding: '16px 18px', borderTop: '1px solid #2A251E', background: '#1B1712' }}>
        <button
          onClick={() => onAdd({
            key: item.id + '-' + Date.now(),
            itemId: item.id,
            name: item.name[lang],
            nameAr: item.name.ar, nameHe: item.name.he,
            basePrice: item.price,
            qty,
            addons: selectedAddons,
            notes: notes.trim(),
          })}
          style={{
            width: '100%', padding: '16px', borderRadius: 12, background: '#C9A24B', color: '#161310',
            fontWeight: 700, fontSize: 16, border: 'none', cursor: 'pointer',
            display: 'flex', alignItems: 'center', justifyContent: 'center', gap: 8
          }}>
          {t.addToCart} · {lineTotal} {t.shekel}
        </button>
      </div>
    </div>
  );
}

