function CheckoutScreen({ t, lang, cart, total, table, onBack, onPaid }) {
  const [method, setMethod] = useState('card'); // card | atTable
  const [processing, setProcessing] = useState(false);
  const [cardNum, setCardNum] = useState('');
  const [expiry, setExpiry] = useState('');
  const [cvv, setCvv] = useState('');
  const BackIcon = lang === 'ar' ? ArrowRight : ArrowLeft;

  const formatCard = (v) => v.replace(/\D/g, '').slice(0, 16).replace(/(\d{4})(?=\d)/g, '$1 ');
  const formatExpiry = (v) => v.replace(/\D/g, '').slice(0, 4).replace(/(\d{2})(?=\d)/, '$1/');

  const canPayCard = cardNum.replace(/\s/g, '').length >= 12 && expiry.length === 5 && cvv.length >= 3;
  const canSubmit = method === 'atTable' ? true : canPayCard;

  const handleSubmit = async () => {
    setProcessing(true);
    if (method === 'card') {
      await new Promise(r => setTimeout(r, 1200));
      await onPaid({ method: 'card_demo', last4: cardNum.replace(/\s/g, '').slice(-4) || '0000', demo: true, paid: true });
    } else {
      await new Promise(r => setTimeout(r, 400));
      await onPaid({ method: 'pay_at_table', paid: false });
    }
    setProcessing(false);
  };

  return (
    <div style={{ minHeight: '100vh', display: 'flex', flexDirection: 'column' }}>
      <div style={{ padding: '14px 16px', borderBottom: '1px solid #2A251E', display: 'flex', alignItems: 'center', gap: 12 }}>
        <button onClick={onBack} disabled={processing} style={{ background: 'none', border: 'none', color: '#C9A24B', cursor: 'pointer', padding: 4 }}>
          <BackIcon size={22} />
        </button>
        <span style={{ fontFamily: 'var(--display)', fontSize: 19, color: '#F2EBDD' }}>{t.checkout}</span>
      </div>

      <div style={{ flex: 1, overflowY: 'auto', padding: '18px 16px' }}>
        <div style={{ background: '#1B1712', border: '1px solid #2A251E', borderRadius: 12, padding: 16, marginBottom: 20 }}>
          <div style={{ color: '#9B9384', fontSize: 13, marginBottom: 10 }}>{t.orderSummary} · {t.table} {table}</div>
          {cart.map(c => {
            const addonsTotal = c.addons.reduce((s, a) => s + a.price, 0);
            const lineTotal = (c.basePrice + addonsTotal) * c.qty;
            return (
              <div key={c.key} style={{ display: 'flex', justifyContent: 'space-between', fontSize: 14, padding: '6px 0', color: '#F2EBDD' }}>
                <span>{c.qty}× {c.name}</span>
                <span>{lineTotal} {t.shekel}</span>
              </div>
            );
          })}
          <div style={{ display: 'flex', justifyContent: 'space-between', borderTop: '1px solid #2A251E', marginTop: 10, paddingTop: 10, fontWeight: 700, color: '#C9A24B' }}>
            <span>{t.total}</span>
            <span>{total} {t.shekel}</span>
          </div>
        </div>

        <div style={{ marginBottom: 20 }}>
          <span style={{ color: '#F2EBDD', fontWeight: 700, fontSize: 15, display: 'block', marginBottom: 10 }}>{t.payMethod}</span>
          <div style={{ display: 'flex', flexDirection: 'column', gap: 10 }}>
            <button onClick={() => setMethod('card')} style={{
              display: 'flex', alignItems: 'center', gap: 12, padding: '14px', borderRadius: 12, cursor: 'pointer',
              border: method === 'card' ? '1.5px solid #C9A24B' : '1px solid #2A251E',
              background: method === 'card' ? 'rgba(201,162,75,0.1)' : '#1B1712', textAlign: lang === 'ar' ? 'right' : 'left'
            }}>
              <span style={{
                width: 20, height: 20, borderRadius: '50%', border: method === 'card' ? '5.5px solid #C9A24B' : '1.5px solid #4A4536',
                flexShrink: 0
              }} />
              <CreditCard size={18} color="#C9A24B" />
              <span style={{ color: '#F2EBDD', fontSize: 14, fontWeight: 600 }}>{t.payByCard}</span>
            </button>
            <button onClick={() => setMethod('atTable')} style={{
              display: 'flex', alignItems: 'flex-start', gap: 12, padding: '14px', borderRadius: 12, cursor: 'pointer',
              border: method === 'atTable' ? '1.5px solid #C9A24B' : '1px solid #2A251E',
              background: method === 'atTable' ? 'rgba(201,162,75,0.1)' : '#1B1712', textAlign: lang === 'ar' ? 'right' : 'left'
            }}>
              <span style={{
                width: 20, height: 20, borderRadius: '50%', border: method === 'atTable' ? '5.5px solid #C9A24B' : '1.5px solid #4A4536',
                flexShrink: 0, marginTop: 1
              }} />
              <span style={{ flex: 1 }}>
                <span style={{ color: '#F2EBDD', fontSize: 14, fontWeight: 600, display: 'block' }}>{t.payAtTable}</span>
                <span style={{ color: '#857C6C', fontSize: 12, display: 'block', marginTop: 2 }}>{t.payAtTableDesc}</span>
              </span>
            </button>
          </div>
        </div>

        {method === 'card' && (
          <>
            <div style={{
              background: 'rgba(201,162,75,0.08)', border: '1px dashed #C9A24B', borderRadius: 10,
              padding: 12, marginBottom: 20, color: '#C9A24B', fontSize: 12.5, display: 'flex', alignItems: 'center', gap: 8
            }}>
              <CreditCard size={16} />
              {t.demoNotice}
            </div>
            <div style={{ display: 'flex', flexDirection: 'column', gap: 12 }}>
              <Field label={t.cardNumber} value={cardNum} onChange={v => setCardNum(formatCard(v))} placeholder="4242 4242 4242 4242" />
              <div style={{ display: 'flex', gap: 12 }}>
                <Field label={t.expiry} value={expiry} onChange={v => setExpiry(formatExpiry(v))} placeholder="MM/YY" style={{ flex: 1 }} />
                <Field label={t.cvv} value={cvv} onChange={v => setCvv(v.replace(/\D/g, '').slice(0, 3))} placeholder="123" style={{ flex: 1 }} />
              </div>
            </div>
          </>
        )}
      </div>

      <div style={{ padding: '16px 18px', borderTop: '1px solid #2A251E', background: '#1B1712' }}>
        <button onClick={handleSubmit} disabled={!canSubmit || processing} style={{
          width: '100%', padding: '16px', borderRadius: 12,
          background: canSubmit && !processing ? '#C9A24B' : '#3A352C',
          color: canSubmit && !processing ? '#161310' : '#6b6457',
          fontWeight: 700, fontSize: 16, border: 'none', cursor: canSubmit && !processing ? 'pointer' : 'not-allowed',
          display: 'flex', alignItems: 'center', justifyContent: 'center', gap: 8
        }}>
          {processing
            ? <><Loader2 size={18} className="animate-spin" /> {t.placingOrder}</>
            : method === 'card' ? `${t.payDemo} · ${total} ${t.shekel}` : `${t.confirmOrder} · ${total} ${t.shekel}`}
        </button>
      </div>
    </div>
  );
}

function Field({ label, value, onChange, placeholder, style }) {
  return (
    <div style={{ ...style }}>
      <label style={{ display: 'block', color: '#9B9384', fontSize: 12, marginBottom: 6 }}>{label}</label>
      <input value={value} onChange={e => onChange(e.target.value)} placeholder={placeholder}
        style={{
          width: '100%', background: '#1B1712', border: '1px solid #2A251E', borderRadius: 10,
          padding: '12px 14px', color: '#F2EBDD', fontSize: 14, boxSizing: 'border-box'
        }} />
    </div>
  );
}

function ConfirmedScreen({ t, lang, order, table, onNewOrder, onTrack }) {
  return (
    <div style={{ minHeight: '100vh', display: 'flex', flexDirection: 'column', alignItems: 'center', justifyContent: 'center', padding: 30, textAlign: 'center' }}>
      <div style={{
        width: 72, height: 72, borderRadius: '50%', background: 'rgba(122,139,115,0.15)',
        border: '2px solid #7A8B73', display: 'flex', alignItems: 'center', justifyContent: 'center', marginBottom: 20
      }}>
        <Check size={32} color="#7A8B73" strokeWidth={2.5} />
      </div>
      <h2 style={{ fontFamily: 'var(--display)', fontSize: 24, color: '#F2EBDD', margin: '0 0 6px' }}>{t.orderPlaced}</h2>
      <p style={{ color: '#9B9384', fontSize: 14, marginBottom: 24 }}>{t.orderPlacedSub}</p>

      <div style={{ background: '#1B1712', border: '1px solid #2A251E', borderRadius: 14, padding: 20, width: '100%', maxWidth: 320 }}>
        <div style={{ display: 'flex', justifyContent: 'space-between', fontSize: 13, color: '#9B9384', marginBottom: 8 }}>
          <span>{t.orderNumber}</span>
          <span style={{ color: '#C9A24B', fontWeight: 700 }}>#{order.number}</span>
        </div>
        <div style={{ display: 'flex', justifyContent: 'space-between', fontSize: 13, color: '#9B9384', marginBottom: 8 }}>
          <span>{t.table}</span>
          <span style={{ color: '#F2EBDD', fontWeight: 600 }}>{table}</span>
        </div>
        <div style={{ display: 'flex', justifyContent: 'space-between', fontSize: 13, color: '#9B9384' }}>
          <span>{t.total}</span>
          <span style={{ color: '#F2EBDD', fontWeight: 600 }}>{order.total} {t.shekel}</span>
        </div>
      </div>

      <button onClick={onTrack} style={{ marginTop: 24, width: '100%', maxWidth: 320, padding: '15px', borderRadius: 12, background: '#C9A24B', color: '#161310', border: 'none', fontWeight: 700, cursor: 'pointer' }}>
        {t.viewOrder}
      </button>
      <button onClick={onNewOrder} style={{ marginTop: 10, width: '100%', maxWidth: 320, padding: '15px', borderRadius: 12, background: 'transparent', color: '#C9A24B', border: '1px solid #3A352C', fontWeight: 600, cursor: 'pointer' }}>
        {t.newOrder}
      </button>
    </div>
  );
}

function TrackingScreen({ t, lang, orders, onNewOrder }) {
  const steps = [
    { key: 'new', label: t.statusNew },
    { key: 'preparing', label: t.statusPreparing },
    { key: 'ready', label: t.statusReady },
    { key: 'done', label: t.statusDone },
  ];

  return (
    <div style={{ minHeight: '100vh', display: 'flex', flexDirection: 'column', padding: '24px 20px' }}>
      <h2 style={{ fontFamily: 'var(--display)', fontSize: 22, color: '#C9A24B', textAlign: 'center', marginBottom: 24 }}>
        {t.myOrders || (lang === 'ar' ? 'طلباتي' : 'ההזמנות שלי')}
      </h2>

      <div style={{ flex: 1, overflowY: 'auto', display: 'flex', flexDirection: 'column', gap: 20 }}>
        {orders.map(order => {
          const currentIdx = Math.max(0, steps.findIndex(s => s.key === order.status));
          return (
            <div key={order.id} style={{ background: '#1B1712', border: '1px solid #2A251E', borderRadius: 14, padding: 18 }}>
              {/* Order number + status */}
              <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: 16 }}>
                <span style={{ color: '#C9A24B', fontSize: 20, fontWeight: 700, fontFamily: 'var(--display)' }}>#{order.number}</span>
                <span style={{
                  background: order.status === 'ready' ? 'rgba(76,175,80,0.15)' : order.status === 'preparing' ? 'rgba(201,162,75,0.15)' : 'rgba(100,100,100,0.15)',
                  color: order.status === 'ready' ? '#81C784' : order.status === 'preparing' ? '#C9A24B' : '#9B9384',
                  borderRadius: 20, padding: '4px 12px', fontSize: 12, fontWeight: 600
                }}>
                  {steps.find(s => s.key === order.status)?.label || order.status}
                </span>
              </div>

              {/* Progress bar */}
              <div style={{ display: 'flex', justifyContent: 'space-between', position: 'relative', marginBottom: 20, padding: '0 6px' }}>
                <div style={{ position: 'absolute', top: 14, left: 24, right: 24, height: 2, background: '#2A251E', zIndex: 0 }} />
                <div style={{ position: 'absolute', top: 14, left: 24, height: 2, background: '#C9A24B', zIndex: 1, width: `${(currentIdx / (steps.length - 1)) * 100}%`, maxWidth: 'calc(100% - 48px)', transition: 'width 0.4s' }} />
                {steps.map((s, i) => (
                  <div key={s.key} style={{ display: 'flex', flexDirection: 'column', alignItems: 'center', gap: 6, zIndex: 2, flex: 1 }}>
                    <div style={{
                      width: 28, height: 28, borderRadius: '50%', display: 'flex', alignItems: 'center', justifyContent: 'center',
                      background: i <= currentIdx ? '#C9A24B' : '#1E1A15', border: i <= currentIdx ? 'none' : '2px solid #3A352C'
                    }}>
                      {i <= currentIdx ? <Check size={14} color="#161310" strokeWidth={3} /> : <span style={{ color: '#6b6457', fontSize: 11 }}>{i + 1}</span>}
                    </div>
                    <span style={{ fontSize: 10, color: i <= currentIdx ? '#F2EBDD' : '#6b6457', textAlign: 'center' }}>{s.label}</span>
                  </div>
                ))}
              </div>

              {/* Items */}
              {order.items.map(c => {
                const addonsTotal = c.addons.reduce((s, a) => s + a.price, 0);
                return (
                  <div key={c.key} style={{ display: 'flex', justifyContent: 'space-between', padding: '6px 0', borderBottom: '1px solid #221E18', fontSize: 13 }}>
                    <span style={{ color: '#F2EBDD' }}>{c.qty}× {c.name}</span>
                    <span style={{ color: '#9B9384' }}>{(c.basePrice + addonsTotal) * c.qty} {t.shekel}</span>
                  </div>
                );
              })}
              <div style={{ display: 'flex', justifyContent: 'space-between', paddingTop: 10, fontWeight: 700, color: '#C9A24B', fontSize: 14 }}>
                <span>{t.total}</span>
                <span>{order.total} {t.shekel}</span>
              </div>
            </div>
          );
        })}
      </div>

      <button onClick={onNewOrder} style={{ marginTop: 16, width: '100%', padding: '15px', borderRadius: 12, background: 'transparent', color: '#C9A24B', border: '1px solid #3A352C', fontWeight: 600, cursor: 'pointer' }}>
        {t.newOrder}
      </button>
    </div>
  );
}

/* ============================================================
   KITCHEN APP
   ============================================================ */
function KitchenApp({ lang, setLang, orders, updateOrder, dbError, goCustomer }) {
  const t = STR[lang];
  const [printOrder, setPrintOrder] = useState(null);

  const updateStatus = (order, status) => {
    updateOrder(order.id, { status });
  };

  const activeOrders = orders.filter(o => o.status !== 'done');
  const cols = [
    { key: 'new', label: t.colNew, items: activeOrders.filter(o => o.status === 'new') },
    { key: 'preparing', label: t.colPreparing, items: activeOrders.filter(o => o.status === 'preparing') },
    { key: 'ready', label: t.colReady, items: activeOrders.filter(o => o.status === 'ready') },
  ];

  return (
    <div dir={t.dir} style={{
      minHeight: '100vh', background: '#161310', color: '#F2EBDD',
      fontFamily: lang === 'ar' ? "'Noto Sans Arabic', sans-serif" : "'Noto Sans Hebrew', sans-serif"
    }}>
      <style>{GLOBAL_CSS}</style>
      <style>{PRINT_CSS}</style>

      <div style={{ padding: '16px 20px', borderBottom: '1px solid #2A251E', display: 'flex', alignItems: 'center', justifyContent: 'space-between' }} className="no-print">
        <div style={{ display: 'flex', alignItems: 'center', gap: 12 }}>
          <ChefHat size={22} color="#C9A24B" />
          <div>
            <div style={{ fontFamily: 'var(--display)', fontSize: 20, color: '#C9A24B' }}>{t.kitchenTitle}</div>
            <div style={{ fontSize: 12, color: '#857C6C' }}>{t.kitchenSub}</div>
          </div>
        </div>
        <div style={{ display: 'flex', gap: 10, alignItems: 'center' }}>
          <LangToggle t={t} lang={lang} setLang={setLang} />
          <button onClick={goCustomer} style={{ fontSize: 11, background: 'none', border: '1px solid #3A352C', borderRadius: 16, padding: '6px 12px', color: '#857C6C', cursor: 'pointer' }}>
            {t.switchToCustomer}
          </button>
        </div>
      </div>
      {dbError && (
        <div className="no-print" style={{
          background: 'rgba(181,87,61,0.15)', borderBottom: '1px solid #B5573D', color: '#B5573D',
          fontSize: 11.5, padding: '8px 20px', textAlign: 'center', wordBreak: 'break-word'
        }}>
          {t.connectionError}: {dbError}
        </div>
      )}

      <div style={{ display: 'flex', gap: 14, padding: 16, overflowX: 'auto' }} className="no-print">
        {cols.map(col => (
          <div key={col.key} style={{ flex: '1 1 0', minWidth: 270 }}>
            <div style={{
              display: 'flex', alignItems: 'center', justifyContent: 'space-between', padding: '10px 14px',
              borderRadius: 10, background: '#1B1712', border: '1px solid #2A251E', marginBottom: 12
            }}>
              <span style={{ fontWeight: 700, fontSize: 14 }}>{col.label}</span>
              <span style={{
                background: col.key === 'new' ? '#B5573D' : col.key === 'preparing' ? '#C9A24B' : '#7A8B73',
                color: '#161310', borderRadius: 12, padding: '2px 9px', fontSize: 12, fontWeight: 700
              }}>{col.items.length}</span>
            </div>

            {col.items.length === 0 && (
              <div style={{ color: '#544E40', fontSize: 13, textAlign: 'center', padding: '24px 0' }}>{t.noOrders}</div>
            )}

            {col.items.map(order => (
              <KitchenTicket key={order.id} t={t} lang={lang} order={order}
                onAdvance={() => {
                  const next = order.status === 'new' ? 'preparing' : order.status === 'preparing' ? 'ready' : 'done';
                  updateStatus(order, next);
                }}
                onPrint={() => { setPrintOrder(order); setTimeout(() => window.print(), 50); }}
              />
            ))}
          </div>
        ))}
      </div>

      {printOrder && <PrintTicket t={t} lang={lang} order={printOrder} />}
    </div>
  );
}

function timeAgo(ts, t) {
  const mins = Math.max(0, Math.floor((Date.now() - ts) / 60000));
  return `${mins}${t.minAgo}`;
}

function KitchenTicket({ t, lang, order, onAdvance, onPrint }) {
  const nextLabel = order.status === 'new' ? t.markPreparing : order.status === 'preparing' ? t.markReady : t.markDone;
  const accentColor = order.status === 'new' ? '#B5573D' : order.status === 'preparing' ? '#C9A24B' : '#7A8B73';

  return (
    <div style={{
      background: '#1B1712', border: '1px solid #2A251E', borderRadius: 12, marginBottom: 12,
      borderInlineStart: `4px solid ${accentColor}`, position: 'relative', overflow: 'hidden'
    }}>
      <div style={{
        backgroundImage: 'radial-gradient(circle, #161310 3px, transparent 3px)',
        backgroundSize: '14px 1px', backgroundPosition: '0 0', height: 1, opacity: 0.6
      }} />
      <div style={{ padding: '12px 14px' }}>
        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'baseline', marginBottom: 8 }}>
          <span style={{ fontFamily: 'var(--display)', fontSize: 17, color: '#C9A24B' }}>#{order.number}</span>
          <span style={{ fontSize: 12, color: '#857C6C', display: 'flex', alignItems: 'center', gap: 4 }}>
            <Clock size={11} /> {timeAgo(order.createdAt, t)}
          </span>
        </div>
        <div style={{ display: 'flex', alignItems: 'center', gap: 8, marginBottom: 10 }}>
          <span style={{ fontSize: 12.5, color: '#9B9384' }}>{t.table} {order.table}</span>
          {order.payment && order.payment.paid === false && (
            <span style={{
              fontSize: 10, fontWeight: 700, color: '#B5573D', background: 'rgba(181,87,61,0.12)',
              border: '1px solid #B5573D', borderRadius: 6, padding: '2px 6px'
            }}>{t.unpaidBadge}</span>
          )}
        </div>

        <div style={{ display: 'flex', flexDirection: 'column', gap: 6, marginBottom: 12 }}>
          {order.items.map(it => (
            <div key={it.key} style={{ fontSize: 13.5 }}>
              <div style={{ color: '#F2EBDD', fontWeight: 600 }}>{it.qty}× {it.name}</div>
              {it.addons.length > 0 && (
                <div style={{ color: '#C9A24B', fontSize: 11.5, marginTop: 1 }}>{it.addons.map(a => `+${a.name}`).join('، ')}</div>
              )}
              {it.notes && <div style={{ color: '#7A8B73', fontSize: 11.5, fontStyle: 'italic' }}>"{it.notes}"</div>}
            </div>
          ))}
        </div>

        <div style={{ display: 'flex', gap: 8 }}>
          <button onClick={onAdvance} style={{
            flex: 1, padding: '10px', borderRadius: 8, border: 'none', cursor: 'pointer',
            background: accentColor, color: '#161310', fontWeight: 700, fontSize: 12.5
          }}>
            {nextLabel}
          </button>
          <button onClick={onPrint} style={{
            padding: '10px 12px', borderRadius: 8, border: '1px solid #3A352C', background: 'transparent',
            color: '#9B9384', cursor: 'pointer', display: 'flex', alignItems: 'center'
          }}>
            <Printer size={15} />
          </button>
        </div>
      </div>
    </div>
  );
}

function PrintTicket({ t, lang, order }) {
  return (
    <div className="print-only" dir={t.dir} style={{ padding: 16, fontFamily: 'monospace', color: '#000' }}>
      <h2 style={{ textAlign: 'center', margin: '4px 0' }}>Fresh Cafe' &amp; Market</h2>
      <p style={{ textAlign: 'center', margin: '2px 0' }}>#{order.number} — {t.table} {order.table}</p>
      <hr />
      {order.items.map(it => (
        <div key={it.key} style={{ marginBottom: 6 }}>
          <div>{it.qty}× {it.name}</div>
          {it.addons.length > 0 && <div style={{ fontSize: 12 }}>+ {it.addons.map(a => a.name).join(', ')}</div>}
          {it.notes && <div style={{ fontSize: 12 }}>* {it.notes}</div>}
        </div>
      ))}
      <hr />
      <p>{t.total}: {order.total} {t.shekel}</p>
      <p style={{ fontSize: 11 }}>{new Date(order.createdAt).toLocaleString()}</p>
    </div>
  );
}

// ---------- Global styles ----------
const GLOBAL_CSS = `
  @import url('https://fonts.googleapis.com/css2?family=Noto+Serif:wght@600;700&family=Noto+Sans:wght@400;500;600;700&family=Noto+Sans+Arabic:wght@400;500;600;700&family=Noto+Sans+Hebrew:wght@400;500;600;700&display=swap');
  :root { --display: 'Noto Serif', 'Noto Sans Arabic', serif; }
  * { box-sizing: border-box; }
  body { margin: 0; }
  .animate-spin { animation: spin 1s linear infinite; }
  @keyframes spin { to { transform: rotate(360deg); } }
  ::-webkit-scrollbar { width: 6px; height: 6px; }
  ::-webkit-scrollbar-thumb { background: #3A352C; border-radius: 3px; }
  .print-only { display: none; }
`;

const PRINT_CSS = `
  @media print {
    .no-print { display: none !important; }
    .print-only { display: block !important; }
    body { background: #fff !important; }
  }
`;
